const body = $input.first().json.body || $input.first().json;
let lead = {};
try {
  const entry = body.entry?.[0];
  const change = entry?.changes?.[0];
  const value = change?.value;
  if (value?.leads?.[0]) {
    const rawLead = value.leads[0];
    const fieldData = rawLead.field_data || [];
    fieldData.forEach(field => { lead[field.name] = field.values?.[0] || ''; });
    lead.lead_id = rawLead.id;
    lead.form_id = value.form_id;
    lead.page_id = value.page_id;
    lead.ad_id = value.ad_id || '';
    lead.campaign_id = value.campaign_id || '';
  } else { lead = body; }
} catch(e) { lead = body; }
const firstName = lead.first_name || lead.full_name?.split(' ')[0] || '';
const lastName = lead.last_name || lead.full_name?.split(' ').slice(1).join(' ') || '';
const email = lead.email || lead.email_address || '';
const phone = lead.phone_number || lead.phone || '';
return [{ json: { firstName, lastName, email, phone, source: 'Facebook Lead Ads', adId: lead.ad_id || '', campaignId: lead.campaign_id || '', formId: lead.form_id || '', leadId: lead.lead_id || '' } }];

const response = $input.first().json;
const contactId = response.contact?.id || response.id || '';
if (!contactId) throw new Error('GHL contact creation failed: ' + JSON.stringify(response));
return [{ json: { contactId, firstName: $('Parse Facebook Lead').first().json.firstName, email: $('Parse Facebook Lead').first().json.email } }];
